// Merge all fetched data into context for Claude
const webhook = $node['Webhook: Image Ad Copy'].json.body;
const brand = $node['Fetch Brand Profile'].json[0] || {};
const offer = $node['Fetch Offer Context'].json[0] || {};
const swipes = $node['Fetch Swipe Patterns'].json || [];

// Format swipe examples
const swipeExamples = swipes.map((s, i) => 
  `Swipe ${i+1}: Headline: "${s.headline_text || 'N/A'}" | Body: "${s.body_copy || 'N/A'}" | CTA: "${s.cta_text || 'N/A'}" | Angle: ${s.copy_angle || 'N/A'} | Hook: ${s.hook_type || 'N/A'}`
).join('\n');

return [{
  json: {
    webhook,
    brand,
    offer,
    swipe_examples: swipeExamples,
    swipe_count: swipes.length
  }
}];

messages.content:
You are an expert direct response copywriter specializing in image ads (Facebook, Instagram, display). Write copy that SELLS.

BRAND CONTEXT:
- Brand: {{ $json.brand.name || 'Not specified' }}
- Tone: {{ $json.brand.tone || 'Professional, persuasive' }}
- Voice: {{ $json.brand.voice_guidelines || 'Clear, direct, benefit-focused' }}
- Avoid words: {{ ($json.brand.avoid_words || []).join(', ') || 'None specified' }}
- Target audience: {{ $json.brand.target_audience || 'Not specified' }}

OFFER CONTEXT:
- Product: {{ $json.offer.product_name || 'Not specified' }}
- Description: {{ $json.offer.product_description || 'Not specified' }}
- Offer: {{ $json.offer.offer_details || 'Not specified' }}
- Price: {{ $json.offer.price_point || 'Not specified' }}
- Awareness level: {{ $json.offer.awareness_level || 'problem_aware' }}
- Pain points: {{ ($json.offer.pain_points || []).join(', ') || 'Not specified' }}
- Desires: {{ ($json.offer.desires || []).join(', ') || 'Not specified' }}
- Unique mechanism: {{ $json.offer.unique_mechanism || 'Not specified' }}
- Proof points: {{ ($json.offer.proof_points || []).join(', ') || 'Not specified' }}
- ICP: {{ $json.offer.icp || 'Not specified' }}

SWIPE FILE PATTERNS:
{{ $json.swipe_examples || 'No swipes available' }}

FORMAT: {{ $json.webhook.format || '1080x1080' }}
ANGLES TO USE: {{ ($json.webhook.angles || ['problem_agitate', 'curiosity']).join(', ') }}

Generate {{ $json.webhook.num_variants || 5 }} DIFFERENT image ad copy variants. Each must:
1. Use a different persuasion angle from the requested list
2. Match the brand tone and avoid banned words
3. Be appropriate for the awareness level (unaware = educate first, most_aware = go straight for the sale)
4. Be concise enough for an IMAGE AD:
   - Headline: 3-8 words (punchy, scroll-stopping)
   - Body: 1-2 short sentences max
   - CTA: 2-4 words (action-oriented)

Output ONLY valid JSON:
{
  "variants": [
    {
      "headline": "Short punchy headline",
      "body_copy": "Supporting text, 1-2 sentences max",
      "cta": "CTA button text",
      "angle": "which angle this uses",
      "rationale": "1-sentence reason why this angle works for this awareness level"
    }
  ]
}

