// Parse Claude response and create generation record
const data = $input.first().json;
const webhook = $node['Webhook: Image Ad Copy'].json.body;

try {
  let responseText = data.content[0].text;
  responseText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(responseText);

  return [{
    json: {
      success: true,
      generation_id: 'gen-' + Date.now(),
      variants: parsed.variants || [],
      brand_id: webhook.brand_id,
      offer_id: webhook.offer_id,
      swipe_id: webhook.swipe_id
    }
  }];
} catch (e) {
  return [{
    json: {
      success: false,
      error: 'Failed to parse copy variants',
      raw: data.content?.[0]?.text || 'No response'
    }
  }];
}
